--PLEASE PLACE REQUIRED SQL STATEMENT(S) BELOW

-- (a)
ALTER TABLE centre ADD (total_number_offspring NUMBER(6) DEFAULT 0);
commit;

-- (b)
/*
******* Explain here your selected approach and its advantage/s *********
I added two columns to the animal table: one to indicate if the animal is alive or dead,
and another to record the date of death. Using CHAR(1) for status is efficient.
Default values and a check constraint help ensure data integrity and reduce errors.
*/

ALTER TABLE animal ADD (animal_status CHAR(1) DEFAULT 'L');
ALTER TABLE animal ADD CONSTRAINT animal_status_ck CHECK (animal_status IN ('L','D'));
ALTER TABLE animal ADD (death_date DATE);

UPDATE animal SET animal_status = 'D' WHERE animal_id = 5;
UPDATE animal SET death_date = TO_DATE('15-Jan-2021','dd-mon-yyyy') WHERE animal_id = 5;
commit;

-- (c)
ALTER TABLE centre ADD (centre_type VARCHAR2(20) DEFAULT 'Other');
ALTER TABLE centre ADD CONSTRAINT centre_type_ck CHECK (centre_type IN ('Zoo','Wildlife Park','Sanctuary','Nature Reserve','Other'));

UPDATE centre SET centre_type = 'Zoo' WHERE centre_name LIKE '%Zoo%';
UPDATE centre SET centre_type = 'Wildlife Park' WHERE centre_name LIKE '%Park%';
UPDATE centre SET centre_type = 'Sanctuary' WHERE centre_name LIKE '%Sanctuary%';
UPDATE centre SET centre_type = 'Nature Reserve' WHERE centre_name LIKE '%Reserve%';
commit;

