/*Student ID: 29959381*/
/*Student Name: Lai Khairenn*/
/*Tutorial No: Tutorial 5 Friday 10am - 12pm*/

/* Comments for your marker:
For part (b), I chose to add a date_of_death column to the animal table to record when an animal dies, instead of deleting the record. This allows us to keep historical data about all animals, including those that have died, which is useful for reporting and analysis. The approach is demonstrated below.
*/

/*
Task 3:

Complete the listed ALTER and UPDATE actions
*/
/*PLEASE PLACE REQUIRED SQL STATEMENT(S) BELOW*/

/* (a) Add offspring count to centre */
ALTER TABLE centre
ADD (offspring_count NUMBER DEFAULT 0 NOT NULL);

COMMENT ON COLUMN centre.offspring_count IS 'Total number of offspring born at this centre.';

/* (b) Add date_of_death to animal table to record animal deaths */
ALTER TABLE animal
ADD (date_of_death DATE);

COMMENT ON COLUMN animal.date_of_death IS 'Date the animal died, NULL if still alive.';

/*
Approach explanation:
I added a date_of_death column to the animal table. When an animal dies, we update this column with the date of death. This is a "soft delete" approach, which preserves the animal's record for historical and reporting purposes, and avoids issues with foreign key constraints or loss of breeding history. The main advantage is that we retain all data about animals, both living and deceased, and can easily query for living animals (WHERE date_of_death IS NULL) or deceased animals (WHERE date_of_death IS NOT NULL).
*/

/* Demonstrate by marking an animal as deceased (choose any animal bred in a centre, e.g. animal_id = 11) */
UPDATE animal
SET date_of_death = TO_DATE('15-Jan-2021', 'DD-MON-YYYY')
WHERE animal_id = 11;

/* (c) Add centre_type to centre table and update values */
ALTER TABLE centre
ADD (centre_type VARCHAR2(30) DEFAULT 'Other' NOT NULL);

COMMENT ON COLUMN centre.centre_type IS 'Type of centre: Zoo, Wildlife Park, Sanctuary, Nature Reserve, Other.';

/* Update centre_type based on centre_name */
UPDATE centre
SET centre_type = 'Zoo'
WHERE LOWER(centre_name) LIKE '%zoo%';

UPDATE centre
SET centre_type = 'Wildlife Park'
WHERE LOWER(centre_name) LIKE '%park%';

UPDATE centre
SET centre_type = 'Sanctuary'
WHERE LOWER(centre_name) LIKE '%sanctuary%';

UPDATE centre
SET centre_type = 'Nature Reserve'
WHERE LOWER(centre_name) LIKE '%reserve%';

/* All other centres remain as 'Other' by default */

COMMIT;

