    CONSTRAINT pk_species PRIMARY KEY (spec_genus, spec_name)
);

COMMENT ON COLUMN species.spec_genus IS 'The species genus';
COMMENT ON COLUMN species.spec_name IS 'The species name';
COMMENT ON COLUMN species.spec_popular_name IS 'The species popular name';
COMMENT ON COLUMN species.spec_family IS 'The species family name';
COMMENT ON COLUMN species.spec_natural_range IS 'Description of the natural range of the species';

-- Create CENTRE table
CREATE TABLE centre (
    centre_id VARCHAR2(10) NOT NULL,
    centre_name VARCHAR2(100) NOT NULL,
    centre_address VARCHAR2(200),
    centre_director VARCHAR2(50),
    centre_phone_no VARCHAR2(20),
    CONSTRAINT pk_centre PRIMARY KEY (centre_id)
);

COMMENT ON COLUMN centre.centre_id IS 'The identifier for the centre';
COMMENT ON COLUMN centre.centre_name IS 'The centre name';
COMMENT ON COLUMN centre.centre_address IS 'The centre address';
COMMENT ON COLUMN centre.centre_director IS 'The name of the centre director';
COMMENT ON COLUMN centre.centre_phone_no IS 'The centre phone contact number';

-- Create BREEDING_EVENT table
CREATE TABLE breeding_event (
    brevent_id NUMBER(6) NOT NULL,
    brevent_date DATE NOT NULL,
    mother_id NUMBER(6) NOT NULL,
    father_id NUMBER(6) NOT NULL,
    CONSTRAINT pk_breeding_event PRIMARY KEY (brevent_id),
    CONSTRAINT fk_brevent_mother FOREIGN KEY (mother_id) REFERENCES animal(animal_id),
    CONSTRAINT fk_brevent_father FOREIGN KEY (father_id) REFERENCES animal(animal_id)
);

COMMENT ON COLUMN breeding_event.brevent_id IS 'The identifier for the breeding event';
COMMENT ON COLUMN breeding_event.brevent_date IS 'The date on which the breeding event took place';
COMMENT ON COLUMN breeding_event.mother_id IS 'The animal_id of the animal who was the mother';
COMMENT ON COLUMN breeding_event.father_id IS 'The animal_id of the animal who was the father';

-- Create ANIMAL table
CREATE TABLE animal (
    animal_id NUMBER(6) NOT NULL,
    animal_sex CHAR(1) NOT NULL,
    brevent_id NUMBER(6),
    centre_id VARCHAR2(10) NOT NULL,
    spec_genus VARCHAR2(30) NOT NULL,
    spec_name VARCHAR2(30) NOT NULL,
    CONSTRAINT pk_animal PRIMARY KEY (animal_id),
    CONSTRAINT fk_animal_brevent FOREIGN KEY (brevent_id) REFERENCES breeding_event(brevent_id),
    CONSTRAINT fk_animal_centre FOREIGN KEY (centre_id) REFERENCES centre(centre_id),
    CONSTRAINT fk_animal_species FOREIGN KEY (spec_genus, spec_name) REFERENCES species(spec_genus, spec_name),
    CONSTRAINT ck_animal_sex CHECK (animal_sex IN ('M', 'F'))
);

COMMENT ON COLUMN animal.animal_id IS 'The identifier for the animal';
COMMENT ON COLUMN animal.animal_sex IS 'The animal sex (M or F)';
COMMENT ON COLUMN animal.brevent_id IS 'If bred in captivity, the id of the breeding event which produced the animal';
COMMENT ON COLUMN animal.centre_id IS 'The "home" centre where the animal is normally located';
COMMENT ON COLUMN animal.spec_genus IS 'The species genus for the animal';
COMMENT ON COLUMN animal.spec_name IS 'The species name for the animal';

COMMIT;

