def best_schedule(weekly_income, competitions):
    # Input: weekly_income is a list of non-negative integers, competitions is a list of tuples (start, end, winnings)
    # Output: returns the maximum amount of money that can be earned as an integer
    # Time complexity: O(NlogN), where N = len(weekly_income) + len(competitions)
    # Space complexity: O(N)

    n = len(weekly_income)
    profit = [0] * (n + 1)

    # For competitions, we want to process by end_time for DP
    comp_by_end = [[] for _ in range(n)]
    for c in competitions:
        if c[1] < n:
            comp_by_end[c[1]].append(c)

    # Base case: week 0
    profit[0] = 0
    if n > 0:
        profit[1] = max(weekly_income[0], max([c[2] for c in comp_by_end[0]] or [0]))

    for i in range(2, n + 1):
        # Option 1: work as trainer this week
        best = profit[i - 1] + weekly_income[i - 1]
        # Option 2: finish a competition this week
        for c in comp_by_end[i - 1]:
            start, end, win = c
            if profit[start] + win > best:
                best = profit[start] + win
        profit[i] = best

    return profit[n]


def best_itinerary(profit, quarantine_time, home):
    # Input: profit is a list of lists, quarantine_time is a list, home is an int
    # Output: returns the maximum profit as an integer
    # Time complexity: O(nd), n = number of cities, d = number of days
    # Space complexity: O(nd)

    days = len(profit)
    n = len(profit[0])
    dp = [[-1 for _ in range(n)] for _ in range(days + 1)]

    # Start at home city, day 0, can work immediately
    dp[0][home] = 0

    for d in range(days):
        for city in range(n):
            if dp[d][city] == -1:
                continue
            # Option 1: stay and work (if not in quarantine)
            if d < days:
                if d == 0 or dp[d][city] != -1:
                    if dp[d + 1][city] < dp[d][city] + profit[d][city]:
                        dp[d + 1][city] = dp[d][city] + profit[d][city]
            # Option 2: move to adjacent cities
            for move in [-1, 1]:
                next_city = city + move
                if 0 <= next_city < n:
                    q = quarantine_time[next_city]
                    arrive_day = d + 1 + q
                    if arrive_day <= days:
                        if arrive_day < days + 1:
                            if dp[arrive_day][next_city] < dp[d][city]:
                                dp[arrive_day][next_city] = dp[d][city]

    # Find the best profit at the last day
    return max([dp[days][city] for city in range(n) if dp[days][city] != -1] or [0])

