import os
import pandas as pd
import matplotlib.pyplot as plt

class ChessGame:
    def __init__(self, filename, data=()):
        try:
            self.filename = filename
            self.data = data
        except IOError:
            print("IO Error")
        except FileNotFoundError:
            print("File not found")

    # 3.2: Filter out metadata and write game moves to game_string.txt
    def filter_game_data(self):
        try:
            infile = open(self.filename, 'r', errors='ignore')
            outfile = open("game_string.txt", 'w')
        except FileNotFoundError:
            print("File not found")
        except IOError:
            print("IO Error")
        else:
            lines = infile.readlines()
            games = []
            count = -1
            for i in range(len(lines)):
                line = lines[i].strip('\n')
                if line == "":
                    continue
                elif line[0] == "[":
                    continue
                elif line[:2] == "1.":
                    games.append(line)
                    count += 1
                else:
                    if count >= 0:
                        games[count] += " " + line
            # Remove result at end
            for idx in range(len(games)):
                steps = games[idx].split(' ')
                games[idx] = ''
                for s in range(len(steps)-2):
                    games[idx] += steps[s] + " "
            for g in games:
                outfile.write(g.strip() + '\n')
        finally:
            infile.close()
            outfile.close()

    # 3.3: Separate white and black moves into files
    def create_sub_files(self):
        try:
            movefile = open('game_string.txt', 'r')
            os.mkdir("WhiteMove")
            os.mkdir("BlackMove")
        except FileNotFoundError:
            print("File not found")
        except IOError:
            print("IO Error")
        else:
            moves = movefile.readlines()
            for i in range(len(moves)):
                wfile = open("WhiteMove/" + str(i+1) + "w", "w+")
                bfile = open("BlackMove/" + str(i+1) + "b", "w+")
                move = moves[i].strip('\n').split(' ')
                for j in range(len(move)):
                    if move[j] == '':
                        continue
                    if j % 2 == 1:
                        bfile.write(move[j] + ',')
                    else:
                        wfile.write(move[j][move[j].find('.')+1:] + ',')
                wfile.close()
                bfile.close()

    # 3.4: Count first moves using DataFrame
    def dataframe_counts(self):
        WhiteCount = {}
        BlackCount = {}
        for wfile in os.listdir(os.getcwd() + '/WhiteMove'):
            with open('WhiteMove/' + wfile, 'r') as wf:
                first = wf.readline().split(",")
                if first[0] == '':
                    continue
                if first[0] in WhiteCount:
                    WhiteCount[first[0]] += 1
                else:
                    WhiteCount[first[0]] = 1
        for bfile in os.listdir(os.getcwd() + '/BlackMove'):
            with open('BlackMove/' + bfile, 'r') as bf:
                first = bf.readline().split(",")
                if first[0] == '':
                    continue
                if first[0] in BlackCount:
                    BlackCount[first[0]] += 1
                else:
                    BlackCount[first[0]] = 1
        w_df = pd.DataFrame.from_dict(WhiteCount, orient='index', columns=['Count:'])
        b_df = pd.DataFrame.from_dict(BlackCount, orient='index', columns=['Count:'])
        self.data = (w_df, b_df)
        return self.data

    # 3.5: Plot the ten most common first moves
    def plot_top_moves(self):
        White_names = []
        White_counts = []
        Black_names = []
        Black_counts = []
        merged = pd.concat([self.data[0], self.data[1]])
        top10 = merged.sort_values(by='Count:', ascending=False)[:10]
        for i in range(10):
            if top10.index[i] in self.data[0].index:
                White_names.append(top10.index[i])
                White_counts.append(top10.values[i][0])
            else:
                Black_names.append(top10.index[i])
                Black_counts.append(top10.values[i][0])
        plt.bar(White_names, White_counts, width=0.6, color='Gray')
        plt.bar(Black_names, Black_counts, width=0.6, color='Black')
        plt.legend(["White", "Black"])
        plt.xlabel('the ten most common first moves')
        plt.ylabel('Move Count')
        plt.show()

cg = ChessGame("chess_game.pgn")
cg.filter_game_data()
cg.create_sub_files()
print(cg.dataframe_counts())
cg.plot_top_moves()
